const shortcutBank=[{category:"Common",task:"copy selected text, files, or objects",shortcut:"Ctrl + C",explanation:"Ctrl + C copies the selected item so you can paste another copy somewhere else."},{category:"Common",task:"paste copied or cut content",shortcut:"Ctrl + V",explanation:"Ctrl + V pastes the content you copied or cut."},{category:"Common",task:"cut selected text, files, or objects",shortcut:"Ctrl + X",explanation:"Ctrl + X cuts the selected item so it can be moved to another place."},{category:"Common",task:"undo the last action",shortcut:"Ctrl + Z",explanation:"Ctrl + Z reverses your last action. It is a lifesaver when mistakes happen."},{category:"Common",task:"redo an action you have undone",shortcut:"Ctrl + Y",explanation:"Ctrl + Y repeats or restores an action after using Undo."},{category:"Common",task:"save the current document or file",shortcut:"Ctrl + S",explanation:"Ctrl + S saves your work. Press it often to avoid losing progress."},{category:"Common",task:"select everything in the current document or page",shortcut:"Ctrl + A",explanation:"Ctrl + A selects all visible text, files, cells, or items depending on the program."},{category:"Common",task:"print the current document or page",shortcut:"Ctrl + P",explanation:"Ctrl + P opens the print window."},{category:"Common",task:"find a word or item quickly",shortcut:"Ctrl + F",explanation:"Ctrl + F opens Find/Search so you can locate text quickly."},{category:"Windows",task:"open File Explorer",shortcut:"Windows + E",explanation:"Windows + E opens File Explorer so you can access drives, folders, and files."},{category:"Windows",task:"show or hide the desktop",shortcut:"Windows + D",explanation:"Windows + D minimizes open windows and shows the desktop. Press it again to restore them."},{category:"Windows",task:"lock the computer quickly",shortcut:"Windows + L",explanation:"Windows + L locks the computer and helps protect your work."},{category:"Windows",task:"switch between open apps",shortcut:"Alt + Tab",explanation:"Alt + Tab helps you move between open windows and apps quickly."},{category:"Windows",task:"take a screenshot and copy it to the clipboard",shortcut:"Print Screen",explanation:"Print Screen captures the screen and copies it for pasting into another program."},{category:"Windows",task:"open the Run command box",shortcut:"Windows + R",explanation:"Windows + R opens Run, which can launch programs and system commands."},{category:"Windows",task:"open Task Manager quickly",shortcut:"Ctrl + Shift + Esc",explanation:"Ctrl + Shift + Esc opens Task Manager directly."},{category:"Microsoft Word",task:"make selected text bold",shortcut:"Ctrl + B",explanation:"Ctrl + B applies or removes bold formatting in Word and many other programs."},{category:"Microsoft Word",task:"underline selected text",shortcut:"Ctrl + U",explanation:"Ctrl + U applies or removes underline formatting."},{category:"Microsoft Word",task:"make selected text italic",shortcut:"Ctrl + I",explanation:"Ctrl + I applies or removes italic formatting."},{category:"Microsoft Word",task:"align text to the center",shortcut:"Ctrl + E",explanation:"Ctrl + E centers the selected paragraph or current line in Microsoft Word."},{category:"Microsoft Word",task:"align text to the left",shortcut:"Ctrl + L",explanation:"Ctrl + L aligns the selected paragraph or current line to the left."},{category:"Microsoft Word",task:"justify paragraph text",shortcut:"Ctrl + J",explanation:"Ctrl + J spreads text evenly between the left and right margins."},{category:"Microsoft Word",task:"increase font size",shortcut:"Ctrl + Shift + >",explanation:"Ctrl + Shift + > increases the size of selected text in Word."},{category:"Microsoft Excel",task:"edit the active cell",shortcut:"F2",explanation:"F2 lets you edit the active Excel cell without retyping everything."},{category:"Microsoft Excel",task:"start a formula with AutoSum",shortcut:"Alt + =",explanation:"Alt + = quickly inserts the SUM function for nearby numbers."},{category:"Microsoft Excel",task:"move to the next cell on the right",shortcut:"Tab",explanation:"Tab moves the active cell to the right in Excel."},{category:"Microsoft Excel",task:"move to the cell below",shortcut:"Enter",explanation:"Enter confirms your entry and usually moves the active cell down."},{category:"Microsoft Excel",task:"open the Format Cells dialog box",shortcut:"Ctrl + 1",explanation:"Ctrl + 1 opens Format Cells where you can change number, alignment, font, border, and more."},{category:"Microsoft Excel",task:"insert the current date",shortcut:"Ctrl + ;",explanation:"Ctrl + ; inserts today's date into the active Excel cell."},{category:"Microsoft Excel",task:"insert a new worksheet",shortcut:"Shift + F11",explanation:"Shift + F11 creates a new worksheet in the current workbook."},{category:"Browser",task:"open a new browser tab",shortcut:"Ctrl + T",explanation:"Ctrl + T opens a new tab in most browsers."},{category:"Browser",task:"close the current browser tab",shortcut:"Ctrl + W",explanation:"Ctrl + W closes the current tab or document window."},{category:"Browser",task:"reopen the last closed browser tab",shortcut:"Ctrl + Shift + T",explanation:"Ctrl + Shift + T brings back the most recently closed tab."},{category:"Browser",task:"refresh or reload the current page",shortcut:"Ctrl + R",explanation:"Ctrl + R reloads the current web page. F5 can also refresh a page."},{category:"Browser",task:"move to the address bar",shortcut:"Ctrl + L",explanation:"Ctrl + L selects the address bar so you can type a website address or search."},{category:"Browser",task:"open browser history",shortcut:"Ctrl + H",explanation:"Ctrl + H opens your browsing history in many browsers."}];const shortcutState={category:"All",questions:[],currentIndex:0,score:0,streak:0,bestStreak:0,answered:false,selectedShortcut:""};const shortcutElements={tabs:document.getElementById("shortcutCategoryTabs"),counter:document.getElementById("shortcutCounter"),score:document.getElementById("shortcutScore"),streak:document.getElementById("shortcutStreak"),categoryName:document.getElementById("shortcutCategoryName"),progressBar:document.getElementById("shortcutProgressBar"),tag:document.getElementById("shortcutTag"),question:document.getElementById("shortcutQuestion"),keyboardPreview:document.getElementById("keyboardPreview"),answerGrid:document.getElementById("shortcutAnswerGrid"),feedback:document.getElementById("shortcutFeedback"),restart:document.getElementById("restartShortcuts"),next:document.getElementById("nextShortcut"),resultSummary:document.getElementById("shortcutResultSummary"),resultCircle:document.getElementById("shortcutResultCircle"),bestPill:document.getElementById("shortcutBestPill"),share:document.getElementById("shareShortcutScore")};function shuffleShortcuts(items){return[...items].sort(()=>Math.random()-0.5);}
function getShortcutBestScore(){return Number(localStorage.getItem("athanasShortcutBestScore")||0);}
function setShortcutBestScore(scorePercent){const best=getShortcutBestScore();if(scorePercent>best){localStorage.setItem("athanasShortcutBestScore",String(scorePercent));}
updateShortcutBestPill();}
function updateShortcutBestPill(){shortcutElements.bestPill.textContent=`Best: ${getShortcutBestScore()}%`;}
function getShortcutPool(category){return category==="All"?shortcutBank:shortcutBank.filter(item=>item.category===category);}
function buildChoices(correctShortcut,category){const sameCategory=getShortcutPool(category).map(item=>item.shortcut).filter(shortcut=>shortcut!==correctShortcut);const allOtherShortcuts=shortcutBank.map(item=>item.shortcut).filter(shortcut=>shortcut!==correctShortcut);const choices=[correctShortcut];shuffleShortcuts(sameCategory).forEach(shortcut=>{if(choices.length<4&&!choices.includes(shortcut))choices.push(shortcut);});shuffleShortcuts(allOtherShortcuts).forEach(shortcut=>{if(choices.length<4&&!choices.includes(shortcut))choices.push(shortcut);});return shuffleShortcuts(choices);}
function renderKeyPreview(shortcutText,hidden=true){const text=hidden?shortcutText.replace(/[^+]/g,"?"):shortcutText;const parts=hidden?shortcutText.split("+").map(()=>"?"):shortcutText.split("+").map(part=>part.trim());shortcutElements.keyboardPreview.innerHTML=parts.map((part,index)=>{const plus=index<parts.length-1?'<span class="key-plus">+</span>':'';return`<span class="keycap">${part.trim() || "?"}</span>${plus}`;}).join("");}
function startShortcutTraining(category=shortcutState.category){shortcutState.category=category;const pool=getShortcutPool(category);shortcutState.questions=shuffleShortcuts(pool).slice(0,Math.min(12,pool.length));shortcutState.currentIndex=0;shortcutState.score=0;shortcutState.streak=0;shortcutState.bestStreak=0;shortcutState.answered=false;shortcutState.selectedShortcut="";shortcutElements.resultSummary.textContent="Answer the shortcut questions and your result will appear here.";shortcutElements.resultCircle.textContent="0%";shortcutElements.next.textContent="Next Shortcut";renderShortcutQuestion();}
function renderShortcutQuestion(){const current=shortcutState.questions[shortcutState.currentIndex];shortcutState.answered=false;shortcutState.selectedShortcut="";shortcutElements.counter.textContent=`${shortcutState.currentIndex + 1} / ${shortcutState.questions.length}`;shortcutElements.score.textContent=String(shortcutState.score);shortcutElements.streak.textContent=`${shortcutState.streak} 🔥`;shortcutElements.categoryName.textContent=shortcutState.category==="All"?"All Shortcuts":shortcutState.category;shortcutElements.tag.textContent=current.category;shortcutElements.question.textContent=current.task;shortcutElements.feedback.className="feedback-box";shortcutElements.feedback.textContent="";shortcutElements.progressBar.style.width=`${(shortcutState.currentIndex / shortcutState.questions.length) * 100}%`;shortcutElements.next.disabled=true;renderKeyPreview(current.shortcut,true);shortcutElements.answerGrid.innerHTML="";buildChoices(current.shortcut,current.category).forEach(choice=>{const button=document.createElement("button");button.type="button";button.className="answer-btn shortcut-choice-btn";button.textContent=choice;button.addEventListener("click",()=>selectShortcutAnswer(button,choice));shortcutElements.answerGrid.appendChild(button);});}
function selectShortcutAnswer(button,choice){if(shortcutState.answered)return;const current=shortcutState.questions[shortcutState.currentIndex];const buttons=shortcutElements.answerGrid.querySelectorAll("button");shortcutState.answered=true;shortcutState.selectedShortcut=choice;buttons.forEach(item=>{item.disabled=true;if(item.textContent===current.shortcut){item.classList.add("correct-answer");}});if(choice===current.shortcut){shortcutState.score+=1;shortcutState.streak+=1;shortcutState.bestStreak=Math.max(shortcutState.bestStreak,shortcutState.streak);button.classList.add("correct-answer");shortcutElements.feedback.className="feedback-box correct";shortcutElements.feedback.innerHTML=`<strong>Correct — keyboard confidence is growing!</strong> ${current.explanation}`;}else{shortcutState.streak=0;button.classList.add("wrong-answer");shortcutElements.feedback.className="feedback-box wrong";shortcutElements.feedback.innerHTML=`<strong>Good attempt — this is how practice works.</strong> The correct shortcut is <strong>${current.shortcut}</strong>. ${current.explanation}`;}
renderKeyPreview(current.shortcut,false);shortcutElements.score.textContent=String(shortcutState.score);shortcutElements.streak.textContent=`${shortcutState.streak} 🔥`;shortcutElements.next.disabled=false;shortcutElements.progressBar.style.width=`${((shortcutState.currentIndex + 1) / shortcutState.questions.length) * 100}%`;if(shortcutState.currentIndex===shortcutState.questions.length-1){shortcutElements.next.textContent="Show Result";}}
function showShortcutResult(){const total=shortcutState.questions.length;const percent=Math.round((shortcutState.score/total)*100);setShortcutBestScore(percent);shortcutElements.resultCircle.textContent=`${percent}%`;shortcutElements.progressBar.style.width="100%";let message="Good start. Keep practicing and your fingers will learn the path — from confusion to clarity.";if(percent>=90){message="Excellent! You are becoming a shortcut master — Athanas Inspires style.";}else if(percent>=70){message="Very good! A little more practice and you will be flying on the keyboard.";}else if(percent>=50){message="Nice effort. Review the missed ones, try again, and do not fear the keyboard.";}
shortcutElements.resultSummary.textContent=`${message} Score: ${shortcutState.score}/${total}. Best streak: ${shortcutState.bestStreak}.`;}
function goToNextShortcut(){if(!shortcutState.answered)return;if(shortcutState.currentIndex<shortcutState.questions.length-1){shortcutState.currentIndex+=1;shortcutElements.next.textContent="Next Shortcut";renderShortcutQuestion();}else{showShortcutResult();shortcutElements.next.disabled=true;}}
function shareShortcutResult(){const total=shortcutState.questions.length||1;const percent=Math.round((shortcutState.score/total)*100);const categoryName=shortcutState.category==="All"?"All Shortcuts":shortcutState.category;const message=`I practiced Computer Shortcut Keys on Athanas Inspires and scored ${shortcutState.score}/${total} (${percent}%) in ${categoryName}. Try it here: https://athanasinspires.com`;const whatsappUrl=`https://wa.me/?text=${encodeURIComponent(message)}`;window.open(whatsappUrl,"_blank","noopener,noreferrer");}
shortcutElements.tabs.addEventListener("click",event=>{const button=event.target.closest("button[data-category]");if(!button)return;shortcutElements.tabs.querySelectorAll("button").forEach(tab=>tab.classList.remove("active"));button.classList.add("active");startShortcutTraining(button.dataset.category);});shortcutElements.restart.addEventListener("click",()=>startShortcutTraining(shortcutState.category));shortcutElements.next.addEventListener("click",goToNextShortcut);shortcutElements.share.addEventListener("click",shareShortcutResult);updateShortcutBestPill();startShortcutTraining("All");